  use_case = '["classic", "common", "place-based"]',
  kanji_meaning_tags = '["tree", "wood", "village", "town"]',
  meaning_zh = '木之之村',
  meaning_en = 'Tree village',
  description_zh = '“木”指繁茂的树木，“村”指宁静的聚落。意指被森林环绕的村庄或在林地旁建立家园的家族。木村姓氏展现出一种温厚、扎实且富有韧性的意境，象征着家族品格如古木般坚贞、性格稳重且具有极强的根基感，给人以正直、可靠且底蕴极其深厚的深刻印象。',
  description_en = 'Meaning "tree village." It refers to a family living in a village surrounded by trees or a settlement established near a forest. The name carries a sense of traditional stability, natural growth, and firm roots, suggesting a character that is reliable, patient, and deeply connected to their community.',
  etymology_en = 'A very common topographic name found throughout Japan. Several branches claim descent from the Fujiwara or Minamoto clans. Historically, it was also used by many local officials and warrior families.',
  kanji_breakdown = '[{"kanji":"木","reading":"ki","meaning_zh":"树木","meaning_en":"tree"},{"kanji":"村","reading":"mura","meaning_zh":"村落","meaning_en":"village"}]',
  kamon_prompt = 'A circular Japanese kamon for the Kimura clan. The design should feature "Two Interlocking Oak Leaves" (Ni-mai Kashiwa) or "Wood" patterns. Minimalist flat design, solid black on a white background, organic symmetry, high contrast.',
  famous_bearers = '[{"name":"木村 拓哉","name_jp":"木村 拓哉","context":"芸能人 | 俳優、歌手（元SMAP、国民的スター） | 1972年 11月 13日"},{"name":"木村 カエラ","name_jp":"木村 カエラ","context":"音楽家 | 歌手、モデル | 1984年 10月 24日"},{"name":"木村 正彦","name_jp":"木村 政彦","context":"スポーツ選手 | 柔道家（「木村の前に木村なく、木村の後に木村なし」） | 1917年 9月 10日"},{"name":"木村 幸子","name_jp":"木村 まどか","context":"芸能人 | 声優 | 1980年 1月 28日"}]'
WHERE id = 'fn_kimura__406f0e';

-- 2. Sasaki (佐々木) [fn_sasaki__08f041]
UPDATE names SET 
  vibe = '["noble", "historical", "strong", "rhythmic"]',
  element = '["wood"]',
  use_case = '["classic", "common", "clan-based"]',
  kanji_meaning_tags = '["assist", "help", "tree", "wood"]',
  meaning_zh = '佐助之木',
  meaning_en = 'Helpful tree / Sasaki clan name',
  description_zh = '“佐”指辅助与支持，“々”为叠字号，“木”指树木。意指辅助治世的正义力量或在佐佐木浦居住的豪族。佐々木姓氏展现出一种刚毅、灵动且极具武士底蕴的意境，象征着家族具有忠诚的品格、性格活泼且具备卓越的统率力，给人以干练、正义且底蕴极其显赫的深刻印象。',
  description_en = 'Meaning "helpful tree" or derived from the place name "Sasaki-ura." It is one of the most prestigious warrior surnames in Japanese history. The name evokes a sense of loyalty, martial skill, and rhythmic strength, suggesting a lineage that is both supportive and independently powerful.',
  etymology_en = 'A famous clan-based name. The Sasaki clan claimed descent from the Uda Genji (descendants of Emperor Uda). They were a powerful samurai family that ruled Omi Province and were instrumental in the Kamakura and Muromachi periods.',
