  kamon_prompt = 'A circular Japanese kamon for the Sasaki clan. The design MUST feature "Four Squares" (Yotsume-yui). Minimalist flat design, solid black on a white background, geometric precision, high contrast.',
  famous_bearers = '[{"name":"佐々木 小次郎","name_jp":"佐々木 小次郎","context":"歴史 | 剣豪（宮本武蔵のライバル） | 1585年"},{"name":"佐々木 希","name_jp":"佐々木 希","context":"芸能人 | モデル、俳優 | 1988年 2月 8日"},{"name":"佐々木 朗希","name_jp":"佐々木 朗希","context":"スポーツ選手 | プロ野球選手（「令和の怪物」） | 2001年 11月 3日"},{"name":"佐々木 蔵之介","name_jp":"佐々木 蔵之介","context":"芸能人 | 俳優 | 1968年 2月 4日"}]'
WHERE id = 'fn_sasaki__08f041';

-- 3. Noguchi (野口) [fn_noguchi__436fac]
UPDATE names SET 
