  element = '["earth"]',
  use_case = '["classic", "common", "place-based"]',
  kanji_meaning_tags = '["field", "plain", "mouth", "entrance"]',
  meaning_zh = '原野之口',
  meaning_en = 'Entrance to the field',
  description_zh = '“野”指广阔的原野，“口”指通往内部的入口。意指居住在广袤原野与聚落的交汇点或平原入口处的家族。野口姓氏展现出一种守御、豁达且充满地理枢纽感的意境，象征着家族具有开启机遇的魄力、性格爽朗且根基极其稳固，给人以踏实、大气且底蕴扎实的深刻印象。',
  description_en = 'Meaning "entrance to the field" or "mouth of the plain." It identifies families living at the strategic entry point of a large agricultural area or wild plain. The name suggests a role of openness and guidance, evoking a character that is grounded, observant, and welcoming.',
  etymology_en = 'A very common topographic name found all over Japan. It was often given to those living at the edge of cultivated land or at the entrance to a specific named plain.',
  kanji_breakdown = '[{"kanji":"野","reading":"no","meaning_zh":"原野、野外","meaning_en":"field/plain"},{"kanji":"口","reading":"guchi","meaning_zh":"入口、门口","meaning_en":"mouth/entrance"}]',
  kamon_prompt = 'A circular Japanese kamon for the Noguchi clan. The design should feature "Three Ivy Leaves" (Mitsu Tsuta) or "Crossed Hawk Feathers". Minimalist flat design, solid black on a white background, balanced botanical lines, high contrast.',
  famous_bearers = '[{"name":"野口 英世","name_jp":"野口 英世","context":"その他 | 細菌学者（千円札の肖像） | 1876年 11月 9日"},{"name":"野口 聡一","name_jp":"野口 聡一","context":"その他 | 宇宙飛行士 | 1965年 4月 15日"},{"name":"野口 健","name_jp":"野口 健","context":"その他 | 登山家 | 1973年 8月 21日"},{"name":"野口 五郎","name_jp":"野口 五郎","context":"芸能人 | 歌手、俳優（新御三家） | 1956年 2月 23日"}]'
WHERE id = 'fn_noguchi__436fac';

-- 4. Matsuo (松尾) [fn_matsuo__a48058]
UPDATE names SET 
  vibe = '["nature", "elegant", "enduring", "mysterious"]',
  element = '["wood", "mountain"]',
  use_case = '["classic", "common", "place-based"]',
  kanji_meaning_tags = '["pine", "tail", "ridge", "end"]',
  meaning_zh = '松岭之尾',
  meaning_en = 'Tail of the pine ridge',
  description_zh = '“松”指长寿常青的松树，“尾”指山脊的末端或缓坡。意指居住在大山余脉松树繁茂处的家族。松尾姓氏展现出一种深邃、高雅且极具文韵的意境，象征着家族品格如雪中青松般坚韧、性格不染尘俗且具有极其持久的生命力，给人以气质高雅、冷静且富有思想深度的深刻印象。',
  description_en = 'Meaning "tail of the pine ridge" or "at the lower end of a pine-covered slope." The name carries a sense of subtle beauty and enduring strength, famously associated with the wandering poet Matsuo Basho. It suggests a character that is patient, reflective, and deeply connected to nature''s cycles.',
  etymology_en = 'A classic topographic name. Often associated with the Matsuo Shrine in Kyoto and the families that guarded or served it. Branches found in both western (Kyushu) and central Japan.',
  kanji_breakdown = '[{"kanji":"松","reading":"matsu","meaning_zh":"松树","meaning_en":"pine tree"},{"kanji":"尾","reading":"o","meaning_zh":"尾端、山脊末端","meaning_en":"tail/ridge end"}]',
  kamon_prompt = 'A circular Japanese kamon for the Matsuo clan. The design should feature "Pine Bark" (Matsukawa-bishi) or stylized "Pine Needles". Minimalist flat design, solid black on a white background, sharp geometric lines, high contrast.',
  famous_bearers = '[{"name":"松尾 芭蕉","name_jp":"松尾 芭蕉","context":"文学者 | 俳人（『おくのほそ道』） | 1644年"},{"name":"松尾 翠","name_jp":"松尾 翠","context":"芸能人 | アナウンサー | 1983年 8月 11日"},{"name":"松尾 スズキ","name_jp":"松尾 スズキ","context":"クリエイター | 演出家、脚本家、俳優 | 1962年 12月 15日"},{"name":"松尾 駿","name_jp":"松尾 駿","context":"芸能人 | お笑いタレント（チョコレートプラネット） | 1982年 8月 18日"}]'
WHERE id = 'fn_matsuo__a48058';

