  meaning_en = 'Long-lasting hollow / Protected valley',
  description_zh = '“久”指时间的绵延，“保”在此处主要指“洼地”（古语通“洼”）。意指居住在被群山环抱、环境安宁的避风洼地中的家族。久保姓氏展现出一种敦厚、宁静且极具守护感的意境，象征着家族具有长盛不衰的运势、性格平和且根基稳步拓展，给人以踏实、友善且生活底蕴极其扎实的深刻印象。',
  description_en = 'Meaning "long-lasting hollow" or "inhabitant of a sunken land." It refers to families living in a protected basin or hollow that shielded them from the elements. The name suggests a sheltered and enduring prosperity, evoking a character that is peaceful, resilient, and deeply rooted.',
  etymology_en = 'A very common topographic name. "Kubo" (depression/hollow) is a frequent element in Japanese place names. Many unrelated families took this as a surname based on their protected location.',
  kanji_breakdown = '[{"kanji":"久","reading":"ku","meaning_zh":"悠久、长远","meaning_en":"long time"},{"kanji":"保","reading":"bo (kubo)","meaning_zh":"保持、安宁（此处指洼地）","meaning_en":"long time/hollow"}]',
  kamon_prompt = 'A circular Japanese kamon for the Kubo clan. The design should feature "Three Ivy Leaves" (Mitsu Tsuta) or "Crossed Hawk Feathers". Minimalist flat design, solid black on a white background, balanced botanical symmetry, high contrast.',
  famous_bearers = '[{"name":"久保 建英","name_jp":"久保 建英","context":"スポーツ選手 | プロサッカー選手（日本代表） | 2001年 6月 4日"},{"name":"久保 帯人","name_jp":"久保 帯人","context":"クリエイター | 漫画家（『BLEACH』作者） | 1977年 6月 26日"},{"name":"久保 史緒里","name_jp":"久保 史緒里","context":"芸能人 | アイドル（乃木坂46） | 2001年 9月 14日"},{"name":"久保 俊一郎","name_jp":"久保 俊一郎","context":"芸能人 | アナウンサー | 1975年 3月 25日"}]'
